mapper.select:
SELECT n.id,
       n.task_id   AS taskId,
       n.type,
       t.title     AS taskTitle,
       p.key       AS projectKey,
       t.seq       AS taskSeq,
       n.read_at   AS readAt,
       n.created_at AS createdAt
FROM notifications n
JOIN tasks t ON t.id = n.task_id AND t.tenant_id = #{tenantId}
JOIN projects p ON p.id = t.project_id AND p.tenant_id = #{tenantId}
WHERE n.user_id = #{userId}
  AND n.tenant_id = #{tenantId}
ORDER BY n.id DESC
LIMIT #{limit}

SELECT COUNT(*)
FROM notifications
WHERE user_id = #{userId}
  AND read_at IS NULL
  AND tenant_id = #{tenantId}

mapper.update:
UPDATE notifications
SET read_at = now()
WHERE id = #{id}
  AND user_id = #{userId}
  AND read_at IS NULL
  AND tenant_id = #{tenantId}

UPDATE notifications
SET read_at = now()
WHERE user_id = #{userId}
  AND read_at IS NULL
  AND tenant_id = #{tenantId}

